vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // PAINTERLY EFFECT:
    vec2 t = 0.005 + 0.045*clamp01(vec2(audioLow,audioHigh)-1);
    vec2 uv2 = vUv;
    vec2 delta2 = uTexSize.zw*vec2(1,1);
    vec3 blurry_color = texture( sampler_main,
        mix(vUv,vUvOriginal,-1) + delta2 ).xyz;
    vec2 v = (blurry_color.xy-0.37) * t;
      //uv2 += v;
      // instead, add a rotated version:
      uv2.x += v.x*q1 + v.y*q2;
      uv2.y += v.x*q2 - v.y*q1;

    // sample previous uFrame
