vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

ret = mix(GetBlur2(vUv),GetPixel(vUv),0.4);

ret = (ret.y-ret.x*0.5)*mix(vec3(1.8,2.3,1.1),1,ret.x)*1.4;
ret *= 1.99; //MilkDrop2077 gamma effect


ret *= vec3(vRadius*3,1,1);

  fragColor = ret;
}
